#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X; scanf("%lld", &X);
        if (X < 333) printf("LIGHT\n");
        else if (X < 777) printf("MODERATE\n");
        else printf("HEAVY\n");
    }
    return 0;
}

