code.Python3:
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        x = int(data[i])
        if x < 333:
            out.append('LIGHT')
        elif x < 777:
            out.append('MODERATE')
        else:
            out.append('HEAVY')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

